public class PostServiceImpl implements PostService {
 private final PostDAO postDAO;
 public PostServiceImpl(PostDAO postDAO) {
 this.postDAO = postDAO;
 }
 private void validate(Post post, Long excludeId) {
 StringBuilder err = new StringBuilder();
 if (post.getTitle() == null || post.getTitle().isBlank())
 err.append("- title không được rỗng.\n");
 else if (post.getTitle().length() > 255)
 err.append("- title tối đa 255 ký tự.\n");
 if (post.getContent() == null || post.getContent().isBlank())
 err.append("- content không được rỗng.\n");
 if (post.getAuthor() == null || post.getAuthor().isBlank())
 err.append("- author không được rỗng.\n");
 if (post.getCategory() == null || post.getCategory().isBlank())
 err.append("- category không được rỗng.\n");
 if (post.getAlias() == null || post.getAlias().isBlank())
 err.append("- alias không được rỗng.\n");
 else if (!post.getAlias().matches("[a-z0-9\\-]+"))
 err.append("- alias chỉ chứa chữ thường, số và dấu '-'.\n");
 else if (postDAO.existsByAlias(post.getAlias(), excludeId))
 err.append("- alias đã tồn tại.\n");
 if (post.getDateCreated() == null)
 post.setDateCreated(LocalDate.now());
 else if (post.getDateCreated().isAfter(LocalDate.now()))
 err.append("- dateCreated không được ở tương lai.\n");
 if (!err.isEmpty()) throw new IllegalArgumentException(err.toString());
 }
