 @Query("SELECT s.courseID, COUNT(s) FROM StudentGrade s GROUP BY s.courseID")
 List<Object[]> countByCourse();
 // b. Đếm số sinh viên có điểm >= 50 theo từng môn
 @Query("SELECT s.courseID, COUNT(s) FROM StudentGrade s WHERE s.stMark >= 50 GROUP BY s.courseID")
 List<Object[]> countByCourseWithPassMark();
}
@Controller
@RequestMapping("/studentgrade")
public class StudentGradeController {
 @Autowired
 private StudentGradeRepository repository;
 // a. Thống kê số lượng sinh viên theo từng môn
